#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, a, b, c, d;
        scanf("%d %d %d %d %d", &N, &a, &b, &c, &d);
        int *strengths = (int*)malloc(N * sizeof(int));
        strengths[0] = d;
        for (int i = 1; i < N; i++) {
            if(i == 1) strengths[i] = (a * d + b * d + c) % 1000000;
            else strengths[i] = (a * strengths[i-2] + b * strengths[i-1] + c) % 1000000;
        }
        qsort(strengths, N, sizeof(int), compare);
        int team1 = 0, team2 = 0;
        for (int i = N - 1; i >= 0; i--) {
            if ((N - 1 - i) % 2 == 0) team1 += strengths[i];
            else team2 += strengths[i];
        }
        printf("%d\n", abs(team1 - team2));
        free(strengths);
    }
    return 0;
}

