const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextInt() {
    return parseInt(lines[idx++]);
}

function nextIntArray() {
    return lines[idx++].split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let [N, a, b, c, d] = nextIntArray();
    let strengths = [d];
    for (let i = 1; i < N; i++) {
        if(i == 1) strengths.push((a * d + b * d + c) % 1000000);
        else strengths.push((a * strengths[i-2] + b * strengths[i-1] + c) % 1000000);
    }
    strengths.sort((x, y) => y - x);
    let team1 = 0, team2 = 0;
    for (let i = 0; i < N; i++) {
        if (i % 2 == 0) team1 += strengths[i];
        else team2 += strengths[i];
    }
    console.log(Math.abs(team1 - team2));
}
